import{_ as t,o as n,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"101. Staffing","description":"","frontmatter":{"title":"101. Staffing","eba":"Mental Health Services 2024-2028","topics":["staffing"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/101-staffing.md","filePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/101-staffing.md"}'),o={name:"ebas/mental-health/rpn-pen-mho/classification-staffing/101-staffing.md"};function r(s,e,l,p,c,h){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_101-staffing" tabindex="-1">101. Staffing <a class="header-anchor" href="#_101-staffing" aria-label="Permalink to &quot;101. Staffing&quot;">​</a></h1><p><strong>101.1</strong> Director of Nursing</p><p><strong>(a)</strong> Each Employer must employ a full-time Mental Health Director of Nursing, classified in accordance with this agreement.</p><p><strong>(b)</strong> Where not already the case, from 1 July 2026, the Director of Nursing role will not have operational responsibility for bed based or community services to enable the prioritisation of the completion of those responsibilities included in subclause 108.16(c). The following positions may report operationally to the position: Nurse Practitioners, Clinical Nurse Consultants, Senior Psychiatric Nurse, and other equivalent mental health nursing roles.</p><p><strong>(c)</strong> The Employer and Unions may agree in writing to vary the restriction in 101.1(b). This agreement may vary the restriction in 101.1(b) for an agreed period of time to enable employers to realign the Director of Nursing workload to release them from any operational responsibilities to ensure they can meet the responsibilities included in 108.16(c).</p><p><strong>(d)</strong> All Mental Health Directors of Nursing appointed before the commencement of this Agreement shall not be disadvantaged by the implementation of the rates of pay for the Director of Nursing Classifications set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> of the 2020 Agreement (see <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> of this Agreement).</p><p><strong>101.2</strong> Senior Psychiatric Nurse Positions</p><p><strong>(a)</strong> In addition to 101.1, each Employer shall ensure that a dedicated full-time senior psychiatric nurse is appointed within each Area Mental Health Service (&#39;AMHS&#39;) for which the Employer was responsible as at 1 October 2000 at level RPN 6 or RPN 7 consistent with the classification standards in this Part.</p><p><strong>(b)</strong> &#39;Dedicated full-time&#39; means an RPN whose clinical duties make up 75% or more of their duties. Clinical duties refers to the overall responsibility for, and co- ordination of, the professional development, education and training program within an Area Mental Health Service and includes roles such as clinical supervision, planning and professional development opportunities and organising student and graduate nurse placements. While the position is not expected to carry a case load, an incumbent may support and advise junior clinicians in the case management of complex clients. The role of the position is differentiated from an operations/program management function, for example Director of Nursing or Community Manager (however titled).</p><p><strong>(c)</strong> The Senior Psychiatric Nurse reports to the Director of Nursing.</p><p><strong>(d)</strong> The senior nursing positions are to extend across all services within an AMHS and are over and above the 23.8 EFT of RPN 4 and 21.4 EFT of RPN 5 positions previously agreed and established and are to be classified in accordance with the allocation at the time (unless amended since).</p><p><strong>101.3</strong> Registered Psychiatric Nurse - Nurse Unit Manager There must be:</p><p><strong>(a)</strong> one EFT Nurse Unit Manager must be appointed in each ward or unit of all residential and in-patient services.</p><p><strong>(b)</strong> two or more part-time Nurse Unit Managers may be appointed so long as one EFT of Nurse Unit Manager hours are worked in the shared position.</p><p><strong>(c)</strong> Subclause (a) does not require the appointment of a Nurse Unit Manager in a CCU or CRP (however titled),where a NUM is not appointed as at 1 July 2016.</p><p><strong>(d)</strong> Nothing in sub-clause (c) above will limit, or in any way change, the Employer’s obligations under clause 101.4 below.</p><p><strong>101.4</strong> Registered Psychiatric Nurse - Associate Nurse Unit Managers</p><p><strong>(a)</strong> ANUMs are appointed to undertake in-charge functions during the off duty periods of the NUM. Subject to the exceptions below, this rate shall be deemed to include the performance of the in-charge function during the off duty periods of the Nurse Unit Manager.</p><p><strong>(b)</strong> 24 Hour a day, seven days per week wards/units</p><p><strong>(c)</strong> The following provisions apply to residential and in-patient services.</p><p><strong>(i)</strong> There must be five EFT ANUM shift positions available for appointment, and four out of the five of the positions must be permanently appointed.</p><p><strong>(ii)</strong> Nothing in any of these provisions prevents ANUM positions being either full-time or part-time.</p><p><strong>(iii)</strong> The 5th EFT of ANUM may be permanently appointed too or may be utilised to provide non-appointed nurses with experience as an ANUM.</p><p><strong>(iv)</strong> In exceptional circumstances, where a minimum of four EFT of ANUMs are permanently appointed, a Registered Psychiatric Nurse other than an ANUM may be required to act in charge during the off-duty period of a NUM. Such a Registered Psychiatric Nurse shall be paid at the minimum rate applicable to the ANUM position which would normally be in charge of the shift.</p><p><strong>(v)</strong> Where less than four EFT of ANUMs are permanently appointed due to recruitment difficulties or delays or to circumstances beyond an Employer&#39;s control, a Registered Psychiatric Nurse, other than an ANUM, may be required to act in charge during the off-duty period of a NUM (which event will be the exception to the rule). Such a Registered Psychiatric Nurse shall be paid at the minimum rate for the Nurse Unit Manager for the entire shift.</p><p><strong>(vi)</strong> Sub-clause 101.4(c)(v) does not apply to a RPN who is required to act in charge in the following circumstances: <strong>(A)</strong> Where an ANUM in whose place the RPN acts, is on any form of leave; or <strong>(B)</strong> For a reasonable period during which a replacement ANUM is sought to be employed to fill a vacancy created by the termination of employment of an ANUM in whose place the RPN acts.</p><p><strong>(vii)</strong> In the circumstances set out in 101.4(c)(vi)(A) or 101.4(c)(vi)(B) the RPN acting in charge shall be paid at the minimum rate applicable to the ANUM position which would normally be in charge of that shift.</p><p><strong>(viii)</strong> If, despite having taken reasonable and practical steps to fill the ANUM positions, an Employer experiences difficulty in recruiting Employees to the permanent ANUM position in order to comply with this clause 101.4, the Employer will contact the relevant workplace delegates and their unions and agree on alternative arrangements.</p><p><strong>101.5</strong> RPN4 - ECT Nurse (Electroconvulsive Therapy Nurse)</p><p><strong>(a)</strong> The RPN responsible for the co-ordination of ECT will be paid at a minimum of RPN4 while performing the functions.</p><p><strong>(b)</strong> The regularity of treatments performed by the service will determine whether or not this function forms part of the regular duties of an individual nurse appointed as RPN4 or is covered by way of higher duties assignment for each treatment session. If managed by way of higher duties, minimum payment will be three hours.</p><p><strong>101.6</strong> Graduate Support Nurse Allocation</p><p><strong>(a)</strong> Employers are required to appoint Graduate Support Nurse (Grade 3) in accordance with <a href="/eba/ebas/mental-health/schedules/11-additional-staffing.html">Schedule 11</a>.</p><p><strong>(b)</strong> For the avoidance of doubt, these positions are in addition to the CNE and CNC (however titled) positions.</p><p><strong>101.7</strong> Clinical Nursing Educator Positions</p><p><strong>(a)</strong> Employers are required to appoint Clinical Nurse Educators (Grade 4) and PEN 4 Educator Support roles in accordance with <a href="/eba/ebas/mental-health/schedules/11-additional-staffing.html">Schedule 11</a>.</p><p><strong>(b)</strong> Employers are required to appoint Clinical Nurse Educator for Parent and Infant Units (Grade 4) in accordance with <a href="/eba/ebas/mental-health/schedules/11-additional-staffing.html">Schedule 11</a> (where applicable).</p><p><strong>101.8</strong> RPN 2 Psychiatric Clinical Nurse Specialist (PCNS) and RPN 2 Advanced</p><p><strong>(a)</strong> An RPN 2 who considers that they meets the criteria set out for RPN 2 Psychiatric Clinical Nurse Specialist or RPN 2 Advanced set out at <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/108-registered-psychiatric-nursing-classifications.html">clause 108.9</a>(c) to 108.9(e) inclusive may apply for reclassification. The application process shall be as set out in <a href="/eba/ebas/mental-health/schedules/04-pcns-and-rpn-2-advanced-application-process.html">Schedule 4</a>.</p><p><strong>(b)</strong> An RPN 2 Advanced shall have the right to be classified as and use the title of RPN 2 PCNS upon the completion of a post graduate course of training in Psychiatric Nursing that leads to endorsement by the NBV.</p><p><strong>(c)</strong> Where relevant, a qualifications allowance will be paid in accordance with the terms of this Agreement.</p><p><strong>(d)</strong> The RPN 2 PCNS and the RPN 2 Advanced are personal classifications. An RPN 2 shall hold the classification while the Employee continues to meet the criteria set out in <a href="/eba/ebas/mental-health/rpn-pen-mho/classification-staffing/108-registered-psychiatric-nursing-classifications.html">clause 108.8</a>(a) of this Agreement. Any performance related issues shall be dealt with in accordance with this existing performance management arrangements of the Employer.</p><p><strong>(e)</strong> All other matters relating to the application process in the assessment criteria are to be as set out in <a href="/eba/ebas/mental-health/schedules/04-pcns-and-rpn-2-advanced-application-process.html">Schedule 4</a> of this Agreement.</p><p><strong>(f)</strong> In order to avoid any confusion, RPNs who are in receipt of commuted allowance and are classified as either RPN 2 PCNS or RPN 2 Advanced shall continue to receive the commuted allowance calculated at the rate of 18% of salary.</p><p><strong>101.9</strong> Skill Mix Inpatient Units</p><p><strong>(a)</strong> The RPN component of an inpatient unit roster will be a minimum of two thirds [2/3rds] of the rostered staff.</p><p><strong>(b)</strong> The remaining one third [1/3rd] of the roster can be filled by PEN staff.</p><p><strong>(c)</strong> The Parties agree to support and facilitate the use of medication endorsement where held by a PEN</p><p><strong>(d)</strong> Subject to the following consideration</p><p><strong>(i)</strong> The skill mix, experience and qualification profiles of the rostered staff, and</p><p><strong>(ii)</strong> Access to other clinical support the 2/3rd: 1/3rd minimum staffing mix for the inpatient units referred to above includes adult acute, aged acute and child and adolescent units (however titled) [CAMHS].</p><p><strong>101.10</strong> Skill Mix Community Mental Health</p><p><strong>(a)</strong> Entry Level Positions</p><p><strong>(i)</strong> The Parties agree to assist in facilitating over the life of the agreement an increase of up to 15% of community mental health staff to be RPN2, PEN or MHO.</p><p><strong>(ii)</strong> In relation to sub-clause (a)[(a)] above the: <strong>(A)</strong> RPN 2 placement shall be a training position and shall comply with the criteria outlined in sub-clause 101.11 below. <strong>(B)</strong> PEN role shall be appropriate to level and experience. Where medication qualification exists, this should be taken into account in role description and work allocated.</p><p><strong>(iii)</strong> MHO role shall be consistent with current classification and role description, that is will not include clinical interventions or treatment provided by RPN/ PEN/ Health Professionals but will provide a support role.</p><p><strong>(b)</strong> Senior Positions</p><p><strong>(i)</strong> A Community Team who has RPN3 in their staffing establishment must also have a RPN4 position within the staffing establishment of the Community Team.</p><p><strong>(ii)</strong> Where the RPN4 position is vacant, a reasonable recruitment process must be undertaken.</p><p><strong>101.11</strong> Community Training Positions</p><p><strong>(a)</strong> Implementation proposals are to be the subject of local consultation including the respective community mental health team and with the Parties.</p><p><strong>(b)</strong> The implementation proposals shall comply with the following criteria:</p><p><strong>(i)</strong> The RPN2/PEN2 training position is a genuine time limited (12 months) training and skills development opportunity with agreed pre-determined educational training requirements and competency assessment.</p><p><strong>(ii)</strong> The development of community trainee positions shall ensure maintenance of the integrity of existing classification standards for community clinician at RPN 3/PEN 3 and above.</p><p><strong>(c)</strong> There shall not be an increase in the case allocation of other clinicians within the team.</p><p><strong>(d)</strong> There can only be a maximum of 1 training position in each CCT, MST, PGAT and/or Integrated team.</p><p><strong>(e)</strong> The Community Training Positions will not undertake CATT assessment and intensive treatment or triage. However, they may accompany an experienced clinician undertaking this work to meet experience and educational requirements.</p><p><strong>(f)</strong> Appropriate supervision arrangements must be in place and detailed in a written supervision agreement that:</p><p><strong>(i)</strong> complies with Department policy, and</p><p><strong>(ii)</strong> is provided by an appropriately experienced RPN at a minimum level of RPN 4 from within the team; and</p><p><strong>(iii)</strong> ensures that the supervision requirements of the supervisor is included their workload.</p><p><strong>(g)</strong> The Community Trainees are to carry a restricted case allocation which meets the following criteria</p><p><strong>(i)</strong> restricted in number and complexity, and</p><p><strong>(ii)</strong> generally stable and well-known patients, and</p><p><strong>(iii)</strong> supervised by more senior clinical staff</p><p><strong>(h)</strong> The Community Trainee shall not act as the primary therapist for any client during the first 3 months of the program.</p><p><strong>(i)</strong> The pay entry points for Community Training Positions are based on the individual’s current level and incremental pay point.</p><p><strong>(j)</strong> The Community Trainee must meet at least the following</p><p><strong>(i)</strong> Current RPN2 / PEN2 with mental health experience, or</p><p><strong>(ii)</strong> New RPN graduates with post graduate qualification</p><p><strong>(k)</strong> Employees without post graduate qualification or mental health experience are excluded</p><p><strong>(l)</strong> On successful completion of the program the Employee shall be appointed to a position in the community in accordance with the classification standards or return to their substantive position.</p><p><strong>101.12</strong> Minimum Staffing Levels - Rural</p><p><strong>(a)</strong> Where an initial community assessment is required, where practicable at least 2 clinicians shall undertake the assessment.</p><p><strong>(b)</strong> If 2 clinicians are unavailable, where practicable support should be sought from emergency services such as police or ambulance officers.</p><p><strong>(c)</strong> If neither of the above situations is available, then where practicable the person to be assessed must be brought to a location that provides a satisfactory clinical environment and level of safety, such as an emergency department.</p><p><strong>101.13</strong> Employment of Agency, Nurse Bank and/or Other Casual Staff In order to ensure the effective operation of the workload management of this Agreement, each Employer will endeavour to fill positions through the employment of ongoing Employees including pool employees. If this is not possible, an Employer should use nurse bank and/or other casual Employees as an interim measure. Agency staff should only be used for unexpected absences, such as sick leave.</p><p><strong>101.14</strong> Graduate Nurses and Nurses undertaking Post Graduate Studies Graduate Nurses and Nurses undertaking Post Graduate studies who have successfully completed their program/course will be offered ongoing employment at the end of their fixed term contract where an appropriately classified vacancy exists.</p>',88)])])}const u=t(o,[["render",r]]);export{g as __pageData,u as default};
